// Build the LLM prompt from the consolidated payload
const payload = items[0].json.payload;
const companiesCompact = payload.companies.map(c => ({
  r: c.rank_consolidated,
  n: c.name,
  ctry: c.country,
  viz: c.visibility_score,
  cited: Object.entries(c.cited_by || {}).filter(([,v]) => v).map(([k]) => k),
  desc: (c.best_description || '').substring(0, 150),
}));

const userPrompt = `Étude ${payload.category} ${payload.year} pour livre blanc 12+ pages.

Données: ${payload.stats.total_unique_companies} sociétés. Stats: ${JSON.stringify(payload.stats)}

${JSON.stringify(companiesCompact)}

JSON STRICT (commence par {):
{
  "executive_summary": "250-300 mots, OUVRE sur LE chiffre marquant. Style FT.",
  "methodology": "200-250 mots: 4 LLM via OpenRouter, dédoublonnage, scoring 0-4.",
  "sector_overview": "350-400 mots vue secteur ${payload.category}: dynamiques, géographie, enjeux 2026.",
  "ai_visibility_analysis": "500-600 mots: pyramide visibilité, analyse par LLM, biais géographique, conséquence pour CMO.",
  "top_companies_summary": [{"rank":1,"name":"...","one_liner":"max 25 mots","ai_visibility_note":"1 phrase","context_note":"1 phrase"}, ...${payload.companies.length} items],
  "insights_and_recommendations": [{"title":"...","body":"100-150 mots"}, ...5 items],
  "about_geoperf": "100-120 mots, mentionne Jourdechance SAS SIREN 838 114 619"
}

Aucun chiffre hors données fournies.`;

const systemPrompt = 'Tu rédiges des études sectorielles institutionnelles pour Geoperf (style FT/Forrester). Sortie : JSON STRICT démarrant par {.';

return [{ json: { ...$('Extract params').item.json, payload, userPrompt, systemPrompt } }];

// Parse the LLM JSON output (tolerant to markdown fences)
const raw = items[0].json.text || '';
let cleaned = raw.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/i, '');
const startIdx = cleaned.indexOf('{');
if (startIdx > 0) cleaned = cleaned.substring(startIdx);
const endIdx = cleaned.lastIndexOf('}');
if (endIdx >= 0) cleaned = cleaned.substring(0, endIdx + 1);
let sections;
try {
  sections = JSON.parse(cleaned);
} catch (e) {
  // Recovery: truncate at last complete section
  let bestEnd = -1, depth = 0, inStr = false, esc = false;
  for (let i = 0; i < cleaned.length; i++) {
    const ch = cleaned[i];
    if (esc) { esc = false; continue; }
    if (ch === '\\' && inStr) { esc = true; continue; }
    if (ch === '"') inStr = !inStr;
    if (inStr) continue;
    if (ch === '{') depth++;
    else if (ch === '}') { depth--; if (depth === 0) bestEnd = i; }
  }
  if (bestEnd > 0) sections = JSON.parse(cleaned.substring(0, bestEnd + 1));
  else throw new Error('Cannot parse LLM JSON: ' + e.message);
}
return [{ json: { ...$('Build synthesis prompt').item.json, sections } }];
